@@\n package com.audaque.model;\n \n+import java.util.List;\n+\n /**\n- * 模板函数定义模型。\n+ * 模板函数定义模型，描述一个可用于数据分析的模板函数。\n+ *\n+ * @param id             唯一标识，如 \"total_rows\"\n+ * @param name           显示名称，如 \"统计总行数\"\n+ * @param category       分类：数据总览 / 数据清洗 / 数据处理 / 数据分析\n+ * @param description    函数功能详细描述\n+ * @param parameters     参数列表\n+ * @param implementation 该函数的伪代码或 Java 实现逻辑\n  */\n-public class TemplateFunction {\n+public record TemplateFunction(\n+        String id,\n+        String name,\n+        String category,\n+        String description,\n+        List\u003cFunctionParameter\u003e parameters,\n+        String implementation) {\n }\ndiff --git a/src/main/resources/template_functions.json b/src/main/resources/template_functions.json\nnew file mode 100644\nindex 0000000..bab3e6c\n--- /dev/null\n+++ b/src/main/resources/template_functions.json\n@@ -0,0 +1,262 @@\n+[\n+  {\n+    \"id\": \"total_rows\",\n+    \"name\": \"统计总行数\",\n+    \"category\": \"数据总览\",\n+    \"description\": \"统计 CSV 数据表中的总行数，包含表头行\",\n+    \"parameters\": [],\n+    \"implementation\": \"// 统计数据集总行数\\nlong totalRows = csvData.getRecords().size();\\nreturn totalRows;\"\n+  },\n+  {\n+    \"id\": \"column_count\",\n+    \"name\": \"统计列数\",\n+    \"category\": \"数据总览\",\n+    \"description\": \"统计 CSV 数据表中的列数\",\n+    \"parameters\": [],\n+    \"implementation\": \"// 根据表头获取列数\\nint columnCount = csvData.getHeader().size();\\nreturn columnCount;\"\n+  },\n+  {\n+    \"id\": \"basic_stats\",\n+    \"name\": \"基本统计量\",\n+    \"category\": \"数据总览\",\n+    \"description\": \"对指定列计算基本统计量，包括计数、均值、中位数、标准差、最小值、最大值、缺失值数和异常值数\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"需要统计的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      }\n+    ],\n+    \"implementation\": \"// 计算某列的基本统计量\\nColumnStat stat = new ColumnStat(columnName, count, mean, median, stdDev, min, max, missingCount, outlierCount);\\nreturn stat;\"\n+  },\n+  {\n+    \"id\": \"remove_nulls\",\n+    \"name\": \"移除空值行\",\n+    \"category\": \"数据清洗\",\n+    \"description\": \"移除包含空值的数据行\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columns\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"检查空值的目标列名列表\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"strategy\",\n+        \"type\": \"STRING\",\n+        \"description\": \"移除策略：ANY（任一列为空则移除）或 ALL（全部为空才移除）\",\n+        \"defaultValue\": \"ANY\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 移除含空值的行\\nList\u003cRecord\u003e cleaned = records.stream()\\n    .filter(r -\u003e columns.stream().noneMatch(col -\u003e r.get(col) == null))\\n    .toList();\\nreturn cleaned;\"\n+  },\n+  {\n+    \"id\": \"remove_outliers\",\n+    \"name\": \"移除异常值\",\n+    \"category\": \"数据清洗\",\n+    \"description\": \"基于 IQR 方法移除指定列的异常值\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"检测异常值的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"iqrMultiplier\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"IQR 乘数，默认 1.5\",\n+        \"defaultValue\": \"1.5\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 基于 IQR 移除异常值\\ndouble q1 = percentile(data, 25);\\ndouble q3 = percentile(data, 75);\\ndouble iqr = q3 - q1;\\ndouble lower = q1 - multiplier * iqr;\\ndouble upper = q3 + multiplier * iqr;\\nreturn data.stream().filter(v -\u003e v \u003e= lower \u0026\u0026 v \u003c= upper).toList();\"\n+  },\n+  {\n+    \"id\": \"fill_missing\",\n+    \"name\": \"填充缺失值\",\n+    \"category\": \"数据清洗\",\n+    \"description\": \"填充数据表中的缺失值\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"需要填充缺失值的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"fillMethod\",\n+        \"type\": \"STRING\",\n+        \"description\": \"填充方法：MEAN（均值）、MEDIAN（中位数）、MODE（众数）、CONSTANT（常量）\",\n+        \"defaultValue\": \"MEAN\",\n+        \"required\": false\n+      },\n+      {\n+        \"name\": \"constantValue\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"当 fillMethod 为 CONSTANT 时的填充值\",\n+        \"defaultValue\": \"0\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 填充缺失值\\ndouble fillValue = switch(fillMethod) {\\n    case \\\"MEAN\\\" -\u003e calculateMean(column);\\n    case \\\"MEDIAN\\\" -\u003e calculateMedian(column);\\n    case \\\"MODE\\\" -\u003e calculateMode(column);\\n    case \\\"CONSTANT\\\" -\u003e Double.parseDouble(constantValue);\\n    default -\u003e 0;\\n};\\nreturn fillMissingWith(column, fillValue);\"\n+  },\n+  {\n+    \"id\": \"normalize\",\n+    \"name\": \"归一化\",\n+    \"category\": \"数据处理\",\n+    \"description\": \"对指定列进行 Min-Max 归一化处理，将数据缩放到指定范围\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"需要归一化的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"minRange\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"目标范围下限\",\n+        \"defaultValue\": \"0\",\n+        \"required\": false\n+      },\n+      {\n+        \"name\": \"maxRange\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"目标范围上限\",\n+        \"defaultValue\": \"1\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// Min-Max 归一化\\ndouble colMin = columnStats.get(columnName).min();\\ndouble colMax = columnStats.get(columnName).max();\\ndouble range = colMax - colMin;\\nreturn data.stream()\\n    .map(v -\u003e minRange + (v - colMin) / range * (maxRange - minRange))\\n    .toList();\"\n+  },\n+  {\n+    \"id\": \"standardize\",\n+    \"name\": \"标准化\",\n+    \"category\": \"数据处理\",\n+    \"description\": \"对指定列进行 Z-Score 标准化处理\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"需要标准化的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      }\n+    ],\n+    \"implementation\": \"// Z-Score 标准化\\ndouble mean = columnStats.get(columnName).mean();\\ndouble stdDev = columnStats.get(columnName).stdDev();\\nreturn data.stream()\\n    .map(v -\u003e (v - mean) / stdDev)\\n    .toList();\"\n+  },\n+  {\n+    \"id\": \"categorize\",\n+    \"name\": \"分类编码\",\n+    \"category\": \"数据处理\",\n+    \"description\": \"将连续数值转换为离散类别\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"需要分类编码的目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"binCount\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"分类数量\",\n+        \"defaultValue\": \"5\",\n+        \"required\": false\n+      },\n+      {\n+        \"name\": \"method\",\n+        \"type\": \"STRING\",\n+        \"description\": \"分类方法：EQUAL_WIDTH（等宽）或 EQUAL_FREQ（等频）\",\n+        \"defaultValue\": \"EQUAL_WIDTH\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 等宽/等频分箱\\ndouble colMin = columnStats.get(columnName).min();\\ndouble colMax = columnStats.get(columnName).max();\\nreturn createBins(data, colMin, colMax, binCount, method);\"\n+  },\n+  {\n+    \"id\": \"correlation\",\n+    \"name\": \"相关性分析\",\n+    \"category\": \"数据分析\",\n+    \"description\": \"计算两列之间的皮尔逊相关系数\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnX\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"第一列列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"columnY\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"第二列列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      }\n+    ],\n+    \"implementation\": \"// 皮尔逊相关系数\\ndouble meanX = columnStats.get(columnX).mean();\\ndouble meanY = columnStats.get(columnY).mean();\\ndouble covariance = 0, stdX = 0, stdY = 0;\\nfor (int i = 0; i \u003c n; i++) {\\n    double dx = get(colX, i) - meanX;\\n    double dy = get(colY, i) - meanY;\\n    covariance += dx * dy;\\n    stdX += dx * dx;\\n    stdY += dy * dy;\\n}\\nreturn covariance / Math.sqrt(stdX * stdY);\"\n+  },\n+  {\n+    \"id\": \"group_by\",\n+    \"name\": \"分组聚合\",\n+    \"category\": \"数据分析\",\n+    \"description\": \"按指定列分组并执行聚合操作\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"groupColumn\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"分组依据列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"aggColumn\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"聚合目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"aggFunction\",\n+        \"type\": \"STRING\",\n+        \"description\": \"聚合函数：SUM、AVG、COUNT、MIN、MAX\",\n+        \"defaultValue\": \"AVG\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 分组聚合\\nMap\u003cString, Double\u003e result = new HashMap\u003c\u003e();\\nfor (Record r : records) {\\n    String key = r.get(groupColumn);\\n    double val = r.get(aggColumn);\\n    result.merge(key, val, Double::sum);\\n}\\nreturn result;\"\n+  },\n+  {\n+    \"id\": \"percentile\",\n+    \"name\": \"百分位数计算\",\n+    \"category\": \"数据分析\",\n+    \"description\": \"计算指定列的百分位数值\",\n+    \"parameters\": [\n+      {\n+        \"name\": \"columnName\",\n+        \"type\": \"COLUMN_REF\",\n+        \"description\": \"目标列名\",\n+        \"defaultValue\": null,\n+        \"required\": true\n+      },\n+      {\n+        \"name\": \"percentile\",\n+        \"type\": \"NUMBER\",\n+        \"description\": \"百分位数值（0-100）\",\n+        \"defaultValue\": \"50\",\n+        \"required\": false\n+      }\n+    ],\n+    \"implementation\": \"// 百分位数计算\\nList\u003cDouble\u003e sorted = data.stream().sorted().toList();\\ndouble k = (sorted.size() - 1) * percentileValue / 100.0;\\nint f = (int) Math.floor(k);\\nint c = (int) Math.ceil(k);\\nreturn (f == c) ? sorted.get(f) : sorted.get(f) * (c - k) + sorted.get(c) * (k - f);\"\n+  }\n+]","modify_time":"2026-07-05 05:37:04","round_id":2,"commit_hash":"cdd414ea127f5fb9f4a51ff6474e0416799788b0"}
 {"prompt_content":"在 com.audaque.parser 包下创建 CsvDataParser 类。实现 parse 方法：接收文件路径 String 参数，使用 Apache Commons CSV 解析 CSV 文件，返回 List\u003cList\u003cDouble\u003e\u003e 数值数据。要求：1）自动检测并跳过表头行；2）将每行数据解析为 Double 列表，非数值单元格跳过并记录警告日志；3）返回所有数值行数据；4）提供 getColumnNames 方法返回列名列表。编写对应的单元测试 CsvDataParserTest（使用 resources/sample.csv 测试）。","agent_type":"Kilo Code","dev_language":"Java","modify_diff":"diff --git a/src/main/java/com/audaque/parser/CsvDataParser.java b/src/main/java/com/audaque/parser/CsvDataParser.java\nindex 3533290..b632b03 100644\n--- a/src/main/java/com/audaque/parser/CsvDataParser.java\n+++ b/src/main/java/com/audaque/parser/CsvDataParser.java\n@@ -1,7 +1,100 @@\n package com.audaque.parser;\n \n+import org.apache.commons.csv.CSVFormat;\n+import org.apache.commons.csv.CSVParser;\n+import org.apache.commons.csv.CSVRecord;\n+import org.slf4j.Logger;\n+import org.slf4j.LoggerFactory;\n+\n+import java.io.FileReader;\n+import java.io.IOException;\n+import java.io.Reader;\n+import java.util.ArrayList;\n+import java.util.Collections;\n+import java.util.List;\n+\n /**\n- * CSV 数据解析器。\n+ * CSV 数据解析器，负责将 CSV 文件解析为数值数据矩阵。\n  */\n public class CsvDataParser {\n+\n+    private static final Logger logger = LoggerFactory.getLogger(CsvDataParser.class);\n+\n+    private List\u003cString\u003e columnNames;\n+\n+    /**\n+     * 构造解析器。\n+     */\n+    public CsvDataParser() {\n+        this.columnNames = Collections.emptyList();\n+    }\n+\n+    /**\n+     * 解析 CSV 文件，自动检测并跳过表头行，将每行数据解析为 Double 列表。\n+     * 非数值单元格将被跳过，并记录警告日志。\n+     *\n+     * @param filePath CSV 文件路径\n+     * @return 所有有效数值行数据，每行为一个 Double 列表\n+     * @throws IOException 文件读取或解析失败\n+     */\n+    public List\u003cList\u003cDouble\u003e\u003e parse(String filePath) throws IOException {\n+        CSVFormat format = CSVFormat.Builder.create()\n+                .setHeader()\n+                .setSkipHeaderRecord(true)\n+                .setIgnoreHeaderCase(true)\n+                .setTrim(true)\n+                .build();\n+\n+        List\u003cList\u003cDouble\u003e\u003e data = new ArrayList\u003c\u003e();\n+\n+        try (Reader reader = new FileReader(filePath);\n+             CSVParser parser = format.parse(reader)) {\n+\n+            this.columnNames = new ArrayList\u003c\u003e(parser.getHeaderNames());\n+            logger.info(\"Detected {} columns: {}\", columnNames.size(), columnNames);\n+\n+            int totalRows = 0;\n+            int validRows = 0;\n+            int skippedCells = 0;\n+\n+            for (CSVRecord record : parser) {\n+                totalRows++;\n+                List\u003cDouble\u003e row = new ArrayList\u003c\u003e();\n+\n+                for (int i = 0; i \u003c columnNames.size(); i++) {\n+                    String cellValue = record.get(i);\n+                    if (cellValue == null || cellValue.isBlank()) {\n+                        skippedCells++;\n+                        continue;\n+                    }\n+                    try {\n+                        row.add(Double.parseDouble(cellValue));\n+                    } catch (NumberFormatException e) {\n+                        skippedCells++;\n+                        logger.warn(\"Skipping non-numeric value \u0027{}\u0027 in column \u0027{}\u0027, row {}\",\n+                                cellValue, columnNames.get(i), totalRows);\n+                    }\n+                }\n+\n+                if (!row.isEmpty()) {\n+                    data.add(row);\n+                    validRows++;\n+                }\n+            }\n+\n+            logger.info(\"Parsed {} total rows: {} valid numeric rows, {} non-numeric cells skipped\",\n+                    totalRows, validRows, skippedCells);\n+        }\n+\n+        return data;\n+    }\n+\n+    /**\n+     * 获取最近一次解析得到的列名列表。\n+     *\n+     * @return 列名列表，未调用 parse 时返回空列表\n+     */\n+    public List\u003cString\u003e getColumnNames() {\n+        return Collections.unmodifiableList(columnNames);\n+    }\n }\ndiff --git a/src/main/java/