me\\\": \\\"columns\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"检查空值的目标列名列表\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"strategy\\\",\\n+        \\\"type\\\": \\\"STRING\\\",\\n+        \\\"description\\\": \\\"移除策略：ANY（任一列为空则移除）或 ALL（全部为空才移除）\\\",\\n+        \\\"defaultValue\\\": \\\"ANY\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 移除含空值的行\\\\nList\\u003cRecord\\u003e cleaned = records.stream()\\\\n    .filter(r -\\u003e columns.stream().noneMatch(col -\\u003e r.get(col) == null))\\\\n    .toList();\\\\nreturn cleaned;\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"remove_outliers\\\",\\n+    \\\"name\\\": \\\"移除异常值\\\",\\n+    \\\"category\\\": \\\"数据清洗\\\",\\n+    \\\"description\\\": \\\"基于 IQR 方法移除指定列的异常值\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"检测异常值的目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"iqrMultiplier\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"IQR 乘数，默认 1.5\\\",\\n+        \\\"defaultValue\\\": \\\"1.5\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 基于 IQR 移除异常值\\\\ndouble q1 = percentile(data, 25);\\\\ndouble q3 = percentile(data, 75);\\\\ndouble iqr = q3 - q1;\\\\ndouble lower = q1 - multiplier * iqr;\\\\ndouble upper = q3 + multiplier * iqr;\\\\nreturn data.stream().filter(v -\\u003e v \\u003e= lower \\u0026\\u0026 v \\u003c= upper).toList();\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"fill_missing\\\",\\n+    \\\"name\\\": \\\"填充缺失值\\\",\\n+    \\\"category\\\": \\\"数据清洗\\\",\\n+    \\\"description\\\": \\\"填充数据表中的缺失值\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"需要填充缺失值的目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"fillMethod\\\",\\n+        \\\"type\\\": \\\"STRING\\\",\\n+        \\\"description\\\": \\\"填充方法：MEAN（均值）、MEDIAN（中位数）、MODE（众数）、CONSTANT（常量）\\\",\\n+        \\\"defaultValue\\\": \\\"MEAN\\\",\\n+        \\\"required\\\": false\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"constantValue\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"当 fillMethod 为 CONSTANT 时的填充值\\\",\\n+        \\\"defaultValue\\\": \\\"0\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 填充缺失值\\\\ndouble fillValue = switch(fillMethod) {\\\\n    case \\\\\\\"MEAN\\\\\\\" -\\u003e calculateMean(column);\\\\n    case \\\\\\\"MEDIAN\\\\\\\" -\\u003e calculateMedian(column);\\\\n    case \\\\\\\"MODE\\\\\\\" -\\u003e calculateMode(column);\\\\n    case \\\\\\\"CONSTANT\\\\\\\" -\\u003e Double.parseDouble(constantValue);\\\\n    default -\\u003e 0;\\\\n};\\\\nreturn fillMissingWith(column, fillValue);\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"normalize\\\",\\n+    \\\"name\\\": \\\"归一化\\\",\\n+    \\\"category\\\": \\\"数据处理\\\",\\n+    \\\"description\\\": \\\"对指定列进行 Min-Max 归一化处理，将数据缩放到指定范围\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"需要归一化的目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"minRange\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"目标范围下限\\\",\\n+        \\\"defaultValue\\\": \\\"0\\\",\\n+        \\\"required\\\": false\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"maxRange\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"目标范围上限\\\",\\n+        \\\"defaultValue\\\": \\\"1\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// Min-Max 归一化\\\\ndouble colMin = columnStats.get(columnName).min();\\\\ndouble colMax = columnStats.get(columnName).max();\\\\ndouble range = colMax - colMin;\\\\nreturn data.stream()\\\\n    .map(v -\\u003e minRange + (v - colMin) / range * (maxRange - minRange))\\\\n    .toList();\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"standardize\\\",\\n+    \\\"name\\\": \\\"标准化\\\",\\n+    \\\"category\\\": \\\"数据处理\\\",\\n+    \\\"description\\\": \\\"对指定列进行 Z-Score 标准化处理\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"需要标准化的目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// Z-Score 标准化\\\\ndouble mean = columnStats.get(columnName).mean();\\\\ndouble stdDev = columnStats.get(columnName).stdDev();\\\\nreturn data.stream()\\\\n    .map(v -\\u003e (v - mean) / stdDev)\\\\n    .toList();\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"categorize\\\",\\n+    \\\"name\\\": \\\"分类编码\\\",\\n+    \\\"category\\\": \\\"数据处理\\\",\\n+    \\\"description\\\": \\\"将连续数值转换为离散类别\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"需要分类编码的目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"binCount\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"分类数量\\\",\\n+        \\\"defaultValue\\\": \\\"5\\\",\\n+        \\\"required\\\": false\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"method\\\",\\n+        \\\"type\\\": \\\"STRING\\\",\\n+        \\\"description\\\": \\\"分类方法：EQUAL_WIDTH（等宽）或 EQUAL_FREQ（等频）\\\",\\n+        \\\"defaultValue\\\": \\\"EQUAL_WIDTH\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 等宽/等频分箱\\\\ndouble colMin = columnStats.get(columnName).min();\\\\ndouble colMax = columnStats.get(columnName).max();\\\\nreturn createBins(data, colMin, colMax, binCount, method);\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"correlation\\\",\\n+    \\\"name\\\": \\\"相关性分析\\\",\\n+    \\\"category\\\": \\\"数据分析\\\",\\n+    \\\"description\\\": \\\"计算两列之间的皮尔逊相关系数\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnX\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"第一列列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"columnY\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"第二列列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 皮尔逊相关系数\\\\ndouble meanX = columnStats.get(columnX).mean();\\\\ndouble meanY = columnStats.get(columnY).mean();\\\\ndouble covariance = 0, stdX = 0, stdY = 0;\\\\nfor (int i = 0; i \\u003c n; i++) {\\\\n    double dx = get(colX, i) - meanX;\\\\n    double dy = get(colY, i) - meanY;\\\\n    covariance += dx * dy;\\\\n    stdX += dx * dx;\\\\n    stdY += dy * dy;\\\\n}\\\\nreturn covariance / Math.sqrt(stdX * stdY);\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"group_by\\\",\\n+    \\\"name\\\": \\\"分组聚合\\\",\\n+    \\\"category\\\": \\\"数据分析\\\",\\n+    \\\"description\\\": \\\"按指定列分组并执行聚合操作\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"groupColumn\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"分组依据列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"aggColumn\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"聚合目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"aggFunction\\\",\\n+        \\\"type\\\": \\\"STRING\\\",\\n+        \\\"description\\\": \\\"聚合函数：SUM、AVG、COUNT、MIN、MAX\\\",\\n+        \\\"defaultValue\\\": \\\"AVG\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 分组聚合\\\\nMap\\u003cString, Double\\u003e result = new HashMap\\u003c\\u003e();\\\\nfor (Record r : records) {\\\\n    String key = r.get(groupColumn);\\\\n    double val = r.get(aggColumn);\\\\n    result.merge(key, val, Double::sum);\\\\n}\\\\nreturn result;\\\"\\n+  },\\n+  {\\n+    \\\"id\\\": \\\"percentile\\\",\\n+    \\\"name\\\": \\\"百分位数计算\\\",\\n+    \\\"category\\\": \\\"数据分析\\\",\\n+    \\\"description\\\": \\\"计算指定列的百分位数值\\\",\\n+    \\\"parameters\\\": [\\n+      {\\n+        \\\"name\\\": \\\"columnName\\\",\\n+        \\\"type\\\": \\\"COLUMN_REF\\\",\\n+        \\\"description\\\": \\\"目标列名\\\",\\n+        \\\"defaultValue\\\": null,\\n+        \\\"required\\\": true\\n+      },\\n+      {\\n+        \\\"name\\\": \\\"percentile\\\",\\n+        \\\"type\\\": \\\"NUMBER\\\",\\n+        \\\"description\\\": \\\"百分位数值（0-100）\\\",\\n+        \\\"defaultValue\\\": \\\"50\\\",\\n+        \\\"required\\\": false\\n+      }\\n+    ],\\n+    \\\"implementation\\\": \\\"// 百分位数计算\\\\nList\\u003cDouble\\u003e sorted = data.stream().sorted().toList();\\\\ndouble k = (sorted.size() - 1) * percentileValue / 100.0;\\\\nint f = (int) Math.floor(k);\\\\nint c = (int) Math.ceil(k);\\\\nreturn (f == c) ? sorted.get(f) : sorted.get(f) * (c - k) + sorted.get(c) * (k - f);\\\"\\n+  }\\n+]\",\"modify_time\":\"2026-07-05 05:37:04\",\"round_id\":2,\"commit_hash\":\"cdd414ea127f5fb9f4a51ff6474e0416799788b0\"}\n+{\"prompt_content\":\"在 com.audaque.parser 包下创建 CsvDataParser 类。实