+                </div>
+                <div class="stat-card">
+                    <div class="stat-label">列名</div>
+                    <div class="stat-value" style="font-size:14px;word-break:break-all;">${String.join(", ", summary.columnNames())}</div>
+                </div>
+            </div>
+        </section>
+
+        <section class="section">
+            <h2>各列统计信息</h2>
+            @if(summary.columnStats().isEmpty())
+                <p style="color:var(--text-secondary);">无列统计信息。</p>
+            @else
+                <div style="overflow-x:auto;">
+                    <table>
+                        <thead>
+                            <tr>
+                                <th>列名</th>
+                                <th>有效值数</th>
+                                <th>均值</th>
+                                <th>中位数</th>
+                                <th>标准差</th>
+                                <th>最小值</th>
+                                <th>最大值</th>
+                                <th>缺失值数</th>
+                                <th>异常值数</th>
+                            </tr>
+                        </thead>
+                        <tbody>
+                            @for(var entry : summary.columnStats().entrySet())
+                                @{
+                                    ColumnStat stat = entry.getValue();
+                                    long countVal = stat.count();
+                                    long missingVal = stat.missingCount();
+                                    long totalVal = countVal + missingVal;
+                                    double missingPct = totalVal > 0 ? (double) missingVal / totalVal * 100 : 0;
+                                    boolean hasOutliers = stat.outlierCount() > 0;
+                                    boolean hasHighMissing = missingPct > 10;
+                                }
+                                <tr>
+                                    <td><strong>${entry.getKey()}</strong></td>
+                                    <td>${countVal}</td>
+                                    <td>${String.format("%.4f", stat.mean())}</td>
+                                    <td>${String.format("%.4f", stat.median())}</td>
+                                    <td>${String.format("%.4f", stat.stdDev())}</td>
+                                    <td>${String.format("%.4f", stat.min())}</td>
+                                    <td>${String.format("%.4f", stat.max())}</td>
+                                    <td>
+                                        @if(missingVal > 0)
+                                            <span class="badge @if(hasHighMissing) badge-warning @else badge-success @endif">${missingVal} (${String.format("%.1f", missingPct)}%)</span>
+                                        @else
+                                            <span class="badge badge-success">0</span>
+                                        @endif
+                                    </td>
+                                    <td>
+                                        @if(hasOutliers)
+                                            <span class="badge badge-danger">${stat.outlierCount()}</span>
+                                        @else
+                                            <span class="badge badge-success">0</span>
+                                        @endif
+                                    </td>
+                                </tr>
+                            @endfor
+                        </tbody>
+                    </table>
+                </div>
+            @endif
+        </section>
+
+        <section class="section">
