+                String emptyBadgeClass = emptyRatio < 5 ? "badge-success" : (emptyRatio < 15 ? "badge-warning" : "badge-danger");
+
+                double validRatio = totalRows > 0 ? (double) validRows / totalRows * 100 : 0;
+                String validQualityLabel = validRatio > 95 ? "良好" : (validRatio > 80 ? "一般" : "较差");
+                String validBadgeClass = validRatio > 95 ? "badge-success" : (validRatio > 80 ? "badge-warning" : "badge-danger");
+
+                long totalOutliers = 0;
+                long totalMissing = 0;
+                for(var entry : summary.columnStats().entrySet()) {
+                    totalOutliers += entry.getValue().outlierCount();
+                    totalMissing += entry.getValue().missingCount();
+                }
+            }
+            <div class="quality-item">
+                <span class="quality-label">空行占比</span>
+                <span>
+                    <span class="badge ${emptyBadgeClass}">${emptyQualityLabel}</span>
+                    <span style="margin-left:8px;color:var(--text-secondary);">${String.format("%.2f", emptyRatio)}% (${emptyRows}/${totalRows})</span>
+                </span>
+            </div>
