+                <span class="quality-label">有效数据占比</span>
+                <span>
+                    <span class="badge ${validBadgeClass}">${validQualityLabel}</span>
+                    <span style="margin-left:8px;color:var(--text-secondary);">${String.format("%.2f", validRatio)}% (${validRows}/${totalRows})</span>
+                </span>
+            </div>
+            <div class="quality-item">
+                <span class="quality-label">缺失值总数</span>
